import os
import csv
import random
import base64
import urllib.request
import urllib.error
import json
from datetime import datetime
from flask import Flask, request, jsonify, render_template

app = Flask(__name__)

RESEND_API_KEY = os.environ.get("RESEND_API_KEY", "")
COMPANY        = "iDealz Lanka Pvt Ltd"
CSV_FILE       = "agreements.csv"
FROM_EMAIL     = "onboarding@resend.dev"   # must be a verified domain in Resend
                                           # OR use onboarding@resend.dev for testing

LOGO_B64 = ""


@app.route("/")
def index():
    return render_template("index.html")


@app.route("/submit", methods=["POST"])
def submit():
    data = request.get_json(force=True)

    for field in ["name", "email", "idz_email", "signature"]:
        if not data.get(field, "").strip():
            return jsonify({"ok": False, "error": f"Missing: {field}"}), 400

    now  = datetime.now()
    date = now.strftime("%d %b %Y, %I:%M %p")
    ref  = "IDZ-" + now.strftime("%y%m%d") + "-" + str(random.randint(100, 999))

    try:
        sig_bytes = base64.b64decode(data["signature"].split(",", 1)[1])
        sig_b64   = base64.b64encode(sig_bytes).decode()
        html_body = _build_email(ref, data, date)

        _send_resend(
            to      = data["email"],
            subject = f"iDealz Collaboration Agreement — {ref}",
            html    = html_body,
            sig_b64 = sig_b64,
            ref     = ref,
        )
        _send_resend(
            to      = data["idz_email"],
            subject = f"Agreement signed — {data['name']} [{ref}]",
            html    = html_body,
            sig_b64 = sig_b64,
            ref     = ref,
        )
        _save_csv(ref, data, date)
        return jsonify({"ok": True, "ref": ref})

    except Exception as exc:
        return jsonify({"ok": False, "error": str(exc)}), 500


@app.route("/agreements")
def view_agreements():
    rows = []
    if os.path.exists(CSV_FILE):
        with open(CSV_FILE, newline="", encoding="utf-8") as f:
            rows = list(csv.DictReader(f))
    return render_template("agreements.html", rows=rows)


def _send_resend(to, subject, html, sig_b64, ref):
    payload = {
        "from": f"iDealz Lanka <{FROM_EMAIL}>",
        "to":   [to],
        "subject": subject,
        "html": html,
        "attachments": [{
            "filename": f"signature-{ref}.png",
            "content":  sig_b64,
        }]
    }
    body = json.dumps(payload).encode("utf-8")
    req  = urllib.request.Request(
        "https://api.resend.com/emails",
        data    = body,
        headers = {
            "Authorization": f"Bearer {RESEND_API_KEY}",
            "Content-Type":  "application/json",
        },
        method = "POST",
    )
    with urllib.request.urlopen(req, timeout=15) as resp:
        result = json.loads(resp.read())
        if "error" in result:
            raise Exception(result["error"])


def _save_csv(ref, data, date):
    exists = os.path.exists(CSV_FILE)
    with open(CSV_FILE, "a", newline="", encoding="utf-8") as f:
        w = csv.writer(f)
        if not exists:
            w.writerow(["Ref","Date","Name","Email","Phone","Handle",
                        "Platform","Content","StartDate","EndDate",
                        "Compensation","AuthorizedBy"])
        w.writerow([
            ref, date,
            data.get("name",""),       data.get("email",""),
            data.get("phone",""),      data.get("handle",""),
            data.get("platform",""),   data.get("content",""),
            data.get("start_date",""), data.get("end_date",""),
            data.get("compensation",""),
            data.get("idz_name","") + (f', {data.get("idz_desg","")}' if data.get("idz_desg") else ""),
        ])


def _build_email(ref, data, date):
    name         = data.get("name", "")
    email        = data.get("email", "")
    phone        = data.get("phone", "-")
    handle       = data.get("handle", "-")
