    start_date   = data.get("start_date", "-")
    end_date     = data.get("end_date", "-")
    period       = f"{start_date} to {end_date}" if start_date not in ("-","") and end_date not in ("-","") else "-"
    idz_name     = data.get("idz_name", "iDealz")
    idz_desg     = data.get("idz_desg", "")
    authorized   = f"{idz_name}, {idz_desg}" if idz_desg else idz_name

